const payload = $json.body;
const phone = payload.message.phone;
const tenantSlug = payload.tenantSlug;
const entities = payload.intent?.entities || {};
const service = entities.service || null;
const dateIso = entities.dateIso || null;
const timeStr = entities.timeStr || null;
const missing = [];
if (!service) missing.push('el *servicio* que deseas (ej: manicure, gel, pedicure)');
if (!dateIso) missing.push('la *fecha* (ej: mañana, el martes, el 15)');
if (!timeStr) missing.push('la *hora* (ej: 3pm, 15:00)');
return [{ json: { phone, tenantSlug, service, dateIso, timeStr, isComplete: missing.length === 0, missing, triggerMsgId: payload.message.messageId } }];
